const industries = [
  { slug: 'sports-management', name: 'Sports Management', subreddits: ['SportsBusiness'] },
  { slug: 'media', name: 'Media', subreddits: ['mediaindustry'] },
  { slug: 'manufacturing', name: 'Manufacturing', subreddits: ['manufacturing'] },
  { slug: 'consulting', name: 'Consulting', subreddits: ['consulting'] },
  { slug: 'contracting', name: 'Contracting', subreddits: ['Construction'] },
  { slug: 'brick-and-mortar', name: 'Brick & Mortar', subreddits: ['retail'] },
  { slug: 'energy', name: 'Energy', subreddits: ['energy'] },
  { slug: 'logistics', name: 'Logistics', subreddits: ['logistics'] },
  { slug: 'real-estate', name: 'Real Estate', subreddits: ['CommercialRealEstate', 'realestateinvesting'] },
  { slug: 'agriculture', name: 'Agriculture', subreddits: ['agriculture'] },
];

// No API key needed — BBC's public RSS feeds.
const newsFeeds = [
  { url: 'http://feeds.bbci.co.uk/news/world/rss.xml', label: 'BBC World' },
  { url: 'http://feeds.bbci.co.uk/news/business/rss.xml', label: 'BBC Business' },
];

// No API key needed — Yahoo Finance's public chart endpoint.
const marketTickers = [
  { symbol: 'SPY', label: 'S&P 500 (SPY)' },
  { symbol: 'XLE', label: 'Energy sector (XLE)' },
  { symbol: 'XLRE', label: 'Real estate sector (XLRE)' },
  { symbol: 'IYT', label: 'Transports (IYT)' },
];

// Swap for your production Vercel URL once deployed. This is the only place
// it needs to be set — everything downstream reads it from here.
const appUrl = 'http://localhost:3000';

const targetDate = new Date().toISOString().slice(0, 10);

return [{
  json: { industries, newsFeeds, marketTickers, appUrl, targetDate },
}];

const { industries } = $('Config').first().json;

const startUrls = [];
const subredditToIndustry = {};

for (const ind of industries) {
  for (const sub of ind.subreddits) {
    // t=day matches this workflow's daily cadence; switch to t=week for a
    // low-traffic subreddit that doesn't get enough posts in 24h.
    startUrls.push({ url: `https://www.reddit.com/r/${sub}/top/?t=day` });
    subredditToIndustry[sub.toLowerCase()] = ind.slug;
  }
}

return [{ json: { startUrls, subredditToIndustry } }];

const { subredditToIndustry } = $('Build Reddit Start URLs').first().json;
const posts = $input.all().map((i) => i.json);
const items = [];
let position = 0;

function communitySlug(raw) {
  if (!raw) return null;
  return String(raw).replace(/^\/?r\//i, '').trim().toLowerCase();
}

for (const post of posts) {
  try {
    // trudax/reddit-scraper-lite's exact field names can shift between actor
    // versions — check a live run's dataset in the Apify console (or the
    // Fetch Reddit Dataset node's output here) and adjust these fallbacks if
    // items come through with missing titles/industries.
    if (post.dataType && post.dataType !== 'post') continue;
    if (!post.title) continue;

    const slug = communitySlug(post.communityName || post.community || post.subreddit);
    const industry = slug ? subredditToIndustry[slug] : null;
    if (!industry) continue; // Couldn't map this back to a tracked industry — skip it.

    const url = post.permalink ? `https://www.reddit.com${post.permalink}` : post.url || null;

    items.push({
      json: {
        key: `reddit-${industry}-${post.id || position}`,
        industry,
        source_type: 'reddit',
        title: post.title,
        url,
        summary: post.body ? String(post.body).slice(0, 400) : null,
        metadata: {
          subreddit: slug,
          score: post.upVotes ?? post.score ?? null,
          comments: post.numberOfComments ?? post.commentsCount ?? null,
        },
        position: position++,
      },
    });
  } catch (e) {
    continue;
  }
}

return items;

const requests = $('Build News Requests').all();
const responses = $input.all();
const items = [];
const MAX_PER_FEED = 5;

function extractTag(block, tag) {
  const m = block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'i'));
  if (!m) return '';
  let val = m[1];
  const cdata = val.match(/^<!\[CDATA\[([\s\S]*)\]\]>$/);
  if (cdata) val = cdata[1];
  return val
    .trim()
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

for (let i = 0; i < Math.min(requests.length, responses.length); i++) {
  try {
    const label = requests[i].json.label;
    const xml = responses[i].json.data || '';
    const blocks = xml.match(/<item>([\s\S]*?)<\/item>/gi) || [];

    let position = 0;
    for (const block of blocks.slice(0, MAX_PER_FEED)) {
      const title = extractTag(block, 'title');
      const link = extractTag(block, 'link');
      const description = extractTag(block, 'description');
      if (!title || !link) continue;

      items.push({
        json: {
          key: `news-${label.toLowerCase().replace(/[^a-z0-9]+/g, '-')}-${position}`,
          industry: null,
          source_type: 'news',
          title,
          url: link,
          summary: description ? description.replace(/<[^>]+>/g, '').slice(0, 400) : null,
          metadata: { source: label },
          position: position++,
        },
      });
    }
  } catch (e) {
    continue; // Skip a feed that returned something unexpected.
  }
}

return items;

const { marketTickers } = $('Config').first().json;
return marketTickers.map((t) => ({
  json: {
    symbol: t.symbol,
    label: t.label,
    requestUrl: `https://query1.finance.yahoo.com/v8/finance/chart/${t.symbol}?interval=1d&range=5d`,
  },
}));

const requests = $('Build Market Requests').all();
const responses = $input.all();
const items = [];

for (let i = 0; i < Math.min(requests.length, responses.length); i++) {
  try {
    const req = requests[i].json;
    const meta = responses[i].json.chart.result[0].meta;
    const price = meta.regularMarketPrice;
    const prevClose = meta.previousClose ?? meta.chartPreviousClose;
    const changePct = prevClose ? ((price - prevClose) / prevClose) * 100 : 0;
    const sign = changePct >= 0 ? '+' : '';

    items.push({
      json: {
        key: `market-${req.symbol}`,
        industry: null,
        source_type: 'market',
        title: `${req.label} ${sign}${changePct.toFixed(2)}%`,
        url: null,
        summary: null,
        metadata: { ticker: req.symbol, change_pct: Math.round(changePct * 100) / 100, price },
        position: i,
      },
    });
  } catch (e) {
    continue; // Skip a ticker that failed to fetch/parse.
  }
}

return items;

const all = $input.all().map((i) => i.json);

// Cap volume per (industry, source_type) group so the digest stays scannable;
// tune these if you want more/less raw material feeding the drill-down pages.
const REDDIT_PER_INDUSTRY = 4;
const NEWS_TOTAL = 10;

const reddit = all.filter((x) => x.source_type === 'reddit');
const news = all.filter((x) => x.source_type === 'news');
const market = all.filter((x) => x.source_type === 'market');

const cappedReddit = [];
const seenPerIndustry = {};
for (const item of reddit) {
  seenPerIndustry[item.industry] = seenPerIndustry[item.industry] || 0;
  if (seenPerIndustry[item.industry] < REDDIT_PER_INDUSTRY) {
    cappedReddit.push(item);
    seenPerIndustry[item.industry]++;
  }
}

const cappedNews = news.slice(0, NEWS_TOTAL);

// Recompute contiguous, zero-based positions within each (industry, source_type)
// group, since capping/merging can leave gaps.
function renumber(list) {
  const counters = {};
  return list.map((item) => {
    const key = `${item.industry}::${item.source_type}`;
    counters[key] = counters[key] ?? 0;
    return { ...item, position: counters[key]++ };
  });
}

const items = renumber([...cappedReddit, ...cappedNews, ...market]);
const { targetDate } = $('Config').first().json;

return [{ json: { items, targetDate } }];

const { items, targetDate } = $input.first().json;

const CATEGORY_SLUGS = ['big_event', 'world_news', 'community_sentiment', 'industry_events', 'finance', 'opportunities'];
const INDUSTRY_SLUGS = $('Config').first().json.industries.map((i) => i.slug);

const itemsForPrompt = items.map((it) => ({
  key: it.key,
  industry: it.industry,
  source_type: it.source_type,
  title: it.title,
  summary: it.summary,
  metadata: it.metadata,
}));

const systemPrompt = `You are the daily synthesis step of a personal industry-intelligence digest.
You will be given a JSON array of raw items scraped today (reddit posts, news articles, market data),
each with a unique "key". Produce the curated "entries" array for the home feed.

Output rules (strict):
- Respond with ONLY a JSON array. No markdown fences, no prose, no explanation before or after.
- Each element: { "category": string, "industry": string|null, "title": string, "body": string, "position": integer, "source_refs": string[] }.
- "category" MUST be one of exactly: ${CATEGORY_SLUGS.join(', ')}.
- "industry", when set, MUST be one of exactly: ${INDUSTRY_SLUGS.join(', ')}. Use null for items with no single industry (world news, broad market moves).
- "source_refs" MUST only contain "key" values from the provided items array. Never invent a key.
- "position" is zero-based order within its category section.

Category guidance:
- big_event: exactly ONE entry, the single most important story or opportunity across everything today.
- world_news: 1-3 entries, industry null, macro/global stories.
- community_sentiment: one entry per industry that had meaningful reddit discussion, synthesizing the overall mood/theme rather than restating one post; source_refs should usually cite multiple reddit items.
- industry_events: notable per-industry news (funding, deals, regulation, launches).
- finance: market-moving items; industry can be null or set if a move is industry-specific.
- opportunities: angles worth paying attention to — where the day's items suggest a business opening, an investment worth watching, or an industry/role gaining momentum. Ground every claim in the given items; do not speculate beyond them.

Keep each "body" to 2-4 sentences. Do not fabricate items or sources beyond what's provided.`;

const userPrompt = `Today's date: ${targetDate}

Raw items:
${JSON.stringify(itemsForPrompt, null, 2)}

Produce the entries array now.`;

return [{ json: { items, targetDate, systemPrompt, userPrompt } }];

const claudeResponse = $input.first().json;
const { items, targetDate } = $('Assemble Items & Cap').first().json;

let text = '';
if (Array.isArray(claudeResponse.content) && claudeResponse.content[0]?.text) {
  text = claudeResponse.content[0].text;
} else {
  throw new Error(`Unexpected Claude response shape: ${JSON.stringify(claudeResponse).slice(0, 500)}`);
}

// Defensive: strip accidental markdown fences if the model adds them despite instructions.
const start = text.indexOf('[');
const end = text.lastIndexOf(']');
if (start === -1 || end === -1) {
  throw new Error(`Could not find a JSON array in Claude's response: ${text.slice(0, 500)}`);
}
const jsonSlice = text.slice(start, end + 1);

let entries;
try {
  entries = JSON.parse(jsonSlice);
} catch (e) {
  throw new Error(`Failed to parse Claude's entries JSON: ${e.message}\n${jsonSlice.slice(0, 500)}`);
}

// Safety net: drop any source_refs the model invented that don't match a real item key.
// The ingest endpoint would reject the WHOLE payload for a dangling ref; better to
// clean it here than lose a whole day's digest over one bad reference.
const validKeys = new Set(items.map((i) => i.key));
for (const entry of entries) {
  entry.source_refs = (entry.source_refs || []).filter((k) => validKeys.has(k));
}

const payload = { date: targetDate, entries, items };
return [{ json: payload }];
